import{_ as e,o as t,c as s,ag as i}from"./chunks/framework.1N8rnUr9.js";const u=JSON.parse('{"title":"REST API","description":"","frontmatter":{},"headers":[],"relativePath":"developer/rest-api.md","filePath":"developer/rest-api.md","lastUpdated":1775715475000}'),n={name:"developer/rest-api.md"};function o(l,a,p,r,h,d){return t(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="rest-api" tabindex="-1">REST API <a class="header-anchor" href="#rest-api" aria-label="Permalink to &quot;REST API&quot;">​</a></h1><p>TubeBay registers its own REST API endpoints under the <code>tubebay/v1</code> namespace. All endpoints require the <code>manage_options</code> capability (WordPress administrator).</p><div class="warning custom-block"><p class="custom-block-title">Internal API</p><p>These REST API endpoints are used internally by the TubeBay admin panel and Setup Wizard. They are not intended as a public API and may change in future versions.</p></div><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>All endpoints require:</p><ul><li>The user to be <strong>logged in</strong> to WordPress</li><li>The user to have the <strong><code>manage_options</code></strong> capability</li><li>A valid <strong>WordPress REST API nonce</strong> (handled automatically by the admin panel)</li></ul><h2 id="base-url" tabindex="-1">Base URL <a class="header-anchor" href="#base-url" aria-label="Permalink to &quot;Base URL&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/wp-json/tubebay/v1/</span></span></code></pre></div><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><h3 id="authentication-connection" tabindex="-1">Authentication &amp; Connection <a class="header-anchor" href="#authentication-connection" aria-label="Permalink to &quot;Authentication &amp; Connection&quot;">​</a></h3><h4 id="handle-connect-oauth-manual" tabindex="-1">Handle Connect (OAuth &amp; Manual) <a class="header-anchor" href="#handle-connect-oauth-manual" aria-label="Permalink to &quot;Handle Connect (OAuth &amp; Manual)&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">POST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/auth/connect</span></span></code></pre></div><p>Unified endpoint to connect a YouTube channel.</p><ul><li><strong>connection_method</strong>: <code>oauth</code> or <code>api</code></li><li><strong>api_key</strong>: (Required if method is <code>api</code>)</li><li><strong>channel_id</strong>: (Required if method is <code>api</code>)</li><li><strong>refresh_token</strong>: (Required if method is <code>oauth</code>)</li></ul><hr><h4 id="test-connection" tabindex="-1">Test Connection <a class="header-anchor" href="#test-connection" aria-label="Permalink to &quot;Test Connection&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">POST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/youtube/test-connection</span></span></code></pre></div><p>Validates credentials and returns channel metadata (title, description).</p><hr><h3 id="library-management" tabindex="-1">Library Management <a class="header-anchor" href="#library-management" aria-label="Permalink to &quot;Library Management&quot;">​</a></h3><h4 id="sync-library-manual" tabindex="-1">Sync Library (Manual) <a class="header-anchor" href="#sync-library-manual" aria-label="Permalink to &quot;Sync Library (Manual)&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/youtube/sync-library</span></span></code></pre></div><p>Triggers an immediate fetch from the YouTube API, bypassing cached transients.</p><hr><h4 id="sync-status" tabindex="-1">Sync Status <a class="header-anchor" href="#sync-status" aria-label="Permalink to &quot;Sync Status&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/youtube/sync-library-status</span></span></code></pre></div><p>Returns the current sync status and the timestamp of the last successful update.</p><hr><h4 id="get-synced-videos" tabindex="-1">Get Synced Videos <a class="header-anchor" href="#get-synced-videos" aria-label="Permalink to &quot;Get Synced Videos&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/youtube/videos</span></span></code></pre></div><p>Fetch synced videos from the local cache with support for searching and sorting.</p><ul><li><strong>search</strong>: (Optional) Filter by title</li><li><strong>sort</strong>: <code>date_desc</code>, <code>date_asc</code>, <code>title_asc</code>, <code>title_desc</code></li><li><strong>page_token</strong>: (Optional) For pagination</li></ul><hr><h3 id="mappings" tabindex="-1">Mappings <a class="header-anchor" href="#mappings" aria-label="Permalink to &quot;Mappings&quot;">​</a></h3><h4 id="get-product-mappings" tabindex="-1">Get Product Mappings <a class="header-anchor" href="#get-product-mappings" aria-label="Permalink to &quot;Get Product Mappings&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/mappings</span></span></code></pre></div><p>Returns the full list of video-to-product mappings.</p><hr><h4 id="update-mapping" tabindex="-1">Update Mapping <a class="header-anchor" href="#update-mapping" aria-label="Permalink to &quot;Update Mapping&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">POST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/mappings</span></span></code></pre></div><p>Creates or updates a mapping between a YouTube Video ID and a WooCommerce Product ID.</p><hr><h3 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h3><h4 id="get-all-settings" tabindex="-1">Get All Settings <a class="header-anchor" href="#get-all-settings" aria-label="Permalink to &quot;Get All Settings&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/settings</span></span></code></pre></div><h4 id="update-settings" tabindex="-1">Update Settings <a class="header-anchor" href="#update-settings" aria-label="Permalink to &quot;Update Settings&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">POST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/settings</span></span></code></pre></div><hr><h3 id="products-woocommerce-wrapper" tabindex="-1">Products (WooCommerce Wrapper) <a class="header-anchor" href="#products-woocommerce-wrapper" aria-label="Permalink to &quot;Products (WooCommerce Wrapper)&quot;">​</a></h3><h4 id="search-products" tabindex="-1">Search Products <a class="header-anchor" href="#search-products" aria-label="Permalink to &quot;Search Products&quot;">​</a></h4><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /wp-json/tubebay/v1/products</span></span></code></pre></div><p>Utility endpoint used by the mapping interface to find WooCommerce products by name or SKU.</p><ul><li><strong>search</strong>: (Required) Search query</li></ul>',53)])])}const g=e(n,[["render",o]]);export{u as __pageData,g as default};
